import { useEffect, useState } from "react";
import API from "../api";

export default function Dashboard() {
  const [stats, setStats] = useState({});

  useEffect(() => {
    API.get("/borrows/stats").then(res => setStats(res.data));
  }, []);

  return (
    <div>
      <h2>📊 Dashboard</h2>
      <p>Total Books: {stats.totalBooks}</p>
      <p>Total Members: {stats.totalMembers}</p>
      <p>Issued Books: {stats.issuedBooks}</p>
      <p>Overdue Books: {stats.overdueBooks}</p>
    </div>
  );
}
